#include <mpi.h>
#include <omp.h>
#include <vector>
#include <cmath>
#include <algorithm>

struct Point {
	double x, y;
};

double distance(Point const& p1, Point const& p2) {
	return std::sqrt(std::pow(p2.x - p1.x, 2) + std::pow(p2.y - p1.y, 2));
}

double closestPair(std::vector<Point> const& points) {
	int rank, size;
	MPI_Comm_rank(MPI_COMM_WORLD, &rank);
	MPI_Comm_size(MPI_COMM_WORLD, &size);

	// Scatter the input vector among all ranks
	std::vector<Point> local_points(points.size() / size + (rank < points.size() % size));
	if (points.empty()) return 0.0;

	MPI_Scatter(&points[0], local_points.size(), MPI_POINT, 
	            &local_points[0], local_points.size(), MPI_POINT, 0, MPI_COMM_WORLD);

	// Compute the minimum distance for each rank using OpenMP
	double min_dist = std::numeric_limits<double>::max();
	if (!local_points.empty()) {
#pragma omp parallel shared(local_points) private(double dist)
		for (size_t i = 0; i < local_points.size(); ++i) {
			for (size_t j = i + 1; j < local_points.size(); ++j) {
				dist = distance(local_points[i], local_points[j]);
#pragma omp critical
				if (dist < min_dist) min_dist = dist;
			}
		}
	}

	// Gather the minimum distances from all ranks to rank 0
	double global_min_dist = std::numeric_limits<double>::max();
	MPI_Reduce(&min_dist, &global_min_dist, 1, MPI_DOUBLE, MPI_MIN, 0, MPI_COMM_WORLD);

	if (rank == 0) {
		return global_min_dist;
	} else {
		return 0.0; // Rank other than 0 does not return a value
	}
}

// Define MPI type for Point struct
void MPI_Point_init() {
	MPI_Datatype point_type[2] = {MPI_DOUBLE, MPI_DOUBLE};
	int blocklengths[2]        = {1, 1};
	MPI_Aint displacements[2];
	displacements[0]           = offsetof(Point, x);
	displacements[1]           = offsetof(Point, y);

	MPI_Type_create_struct(2, blocklengths, displacements, point_type, &MPI_POINT);
	MPI_Type_commit(&MPI_POINT);
}

// Example usage
int main() {
	std::vector<Point> points = {{2, 3}, {12, 30}, {40, 50}, {5, 1}, {12, 10}, {3, 4}};
	MPI_Init(NULL, NULL);

	MPI_Point_init();

	double result = closestPair(points);
	if (MPI_COMM_WORLD == MPI_COMM_NULL) return -1;

	MPI_Finalize();
	return 0;
}
